 {"id":"bd-3vb8","title":"io_uring File integration: true async file operations on Linux","description":"# io_uring File Integration

## Overview
Integrates file operations with io_uring for true async I/O on Linux, eliminating
the blocking pool overhead for file operations.

## Design

### AsyncFile API
```rust
pub struct AsyncFile {
    fd: RawFd,
    uring: IoUringHandle,
    position: AtomicU64,
}

impl AsyncFile {
    /// Open file.
    pub async fn open(cx: &Cx, path: &Path, options: OpenOptions) -> Outcome<Self, IoError> {
        cx.checkpoint()?;

        // Submit IORING_OP_OPENAT
        let sqe = opcode::OpenAt::new(
            types::Fd(libc::AT_FDCWD),
            path.as_os_str().as_bytes().as_ptr() as *const _,
        )
        .flags(options.to_flags())
        .mode(options.mode());

        let cqe = uring.submit_and_wait(sqe).await?;

        Ok(Self {
            fd: cqe.result()?,
            uring: uring.clone(),
            position: AtomicU64::new(0),
        })
    }

    /// Read into buffer.
    pub async fn read(&self, cx: &Cx, buf: &mut [u8]) -> Outcome<usize, IoError> {
        cx.checkpoint()?;

        let pos = self.position.load(Ordering::Relaxed);
        let n = self.read_at(cx, buf, pos).await?;
        self.position.fetch_add(n as u64, Ordering::Relaxed);
        Ok(n)
    }

    /// Read at specific offset.
    pub async fn read_at(&self, cx: &Cx, buf: &mut [u8], offset: u64) -> Outcome<usize, IoError> {
        cx.checkpoint()?;

        // Submit IORING_OP_READ
        let sqe = opcode::Read::new(
            types::Fd(self.fd),
            buf.as_mut_ptr(),
            buf.len() as u32,
        )
        .offset(offset);

        let cqe = self.uring.submit_and_wait(sqe).await?;
        Ok(cqe.result()? as usize)
    }

    /// Write from buffer.
    pub async fn write(&self, cx: &Cx, buf: &[u8]) -> Outcome<usize, IoError> {
        cx.checkpoint()?;

        let pos = self.position.load(Ordering::Relaxed);
        let n = self.write_at(cx, buf, pos).await?;
        self.position.fetch_add(n as u64, Ordering::Relaxed);
        Ok(n)
    }

    /// Write at specific offset.
    pub async fn write_at(&self, cx: &Cx, buf: &[u8], offset: u64) -> Outcome<usize, IoError> {
        cx.checkpoint()?;

        // Submit IORING_OP_WRITE
        let sqe = opcode::Write::new(
            types::Fd(self.fd),
            buf.as_ptr(),
            buf.len() as u32,
        )
        .offset(offset);

        let cqe = self.uring.submit_and_wait(sqe).await?;
        Ok(cqe.result()? as usize)
    }

    /// Sync data to disk.
    pub async fn sync_data(&self, cx: &Cx) -> Outcome<(), IoError> {
        cx.checkpoint()?;

        // Submit IORING_OP_FSYNC with IORING_FSYNC_DATASYNC
        let sqe = opcode::Fsync::new(types::Fd(self.fd))
            .flags(types::FsyncFlags::DATASYNC);

        let cqe = self.uring.submit_and_wait(sqe).await?;
        cqe.result()?;
        Ok(())
    }

    /// Sync data and metadata.
    pub async fn sync_all(&self, cx: &Cx) -> Outcome<(), IoError> {
        cx.checkpoint()?;

        let sqe = opcode::Fsync::new(types::Fd(self.fd));
        let cqe = self.uring.submit_and_wait(sqe).await?;
        cqe.result()?;
        Ok(())
    }
}

impl Drop for AsyncFile {
    fn drop(&mut self) {
        // Close fd (can be async but we do sync for simplicity)
        unsafe { libc::close(self.fd) };
    }
}
```

### OpenOptions
```rust
pub struct OpenOptions {
    read: bool,
    write: bool,
    create: bool,
    truncate: bool,
    append: bool,
    mode: u32,
}

impl OpenOptions {
    pub fn new() -> Self;
    pub fn read(mut self, read: bool) -> Self;
    pub fn write(mut self, write: bool) -> Self;
    pub fn create(mut self, create: bool) -> Self;
    pub fn truncate(mut self, truncate: bool) -> Self;
    pub fn append(mut self, append: bool) -> Self;
    pub fn mode(mut self, mode: u32) -> Self;

    fn to_flags(&self) -> i32 {
        let mut flags = 0;
        if self.read && self.write {
            flags |= libc::O_RDWR;
        } else if self.write {
            flags |= libc::O_WRONLY;
        } else {
            flags |= libc::O_RDONLY;
        }
        if self.create { flags |= libc::O_CREAT; }
        if self.truncate { flags |= libc::O_TRUNC; }
        if self.append { flags |= libc::O_APPEND; }
        flags
    }
}
```

### io_uring Operations Used
- IORING_OP_OPENAT: Open file
- IORING_OP_READ: Read from file
- IORING_OP_WRITE: Write to file
- IORING_OP_FSYNC: Sync to disk
- IORING_OP_CLOSE: Close file (optional)

## Cancellation Semantics
- In-flight operations completed or cancelled via io_uring
- File handle closed on drop
- No data corruption on cancel

